    for (let i = 2; i <= 1000000; i++) {
        if (!isPrime[i]) {
            primes.push(i);
            for (let j = i * i; j <= 1000000; j += i) {
                isPrime[j] = true;
            }
        }
    }

    // BFS to find the minimum number of jumps
    const queue: number[] = [0];
    const visited: boolean[] = new Array(n).fill(false);
    let steps: number = 0;

    while (queue.length > 0) {
        const levelSize: number = queue.length;
        for (let i = 0; i < levelSize; i++) {
            const node: number = queue.shift()!;
            if (node === n - 1) {
                return steps;
            }
            visited[node] = true;

            // Move to adjacent cells
            if (node + 1 < n && !visited[node + 1]) {
                queue.push(node + 1);
            }
            if (node - 1 >= 0 && !visited[node - 1]) {
                queue.push(node - 1);
            }

            // Prime teleportation
            const num: number = nums[node];
            if (isPrime[num]) {
                for (const p of primes) {
                    if (p > num) break;
                    for (let j = 0; j < n; j++) {
                        if (nums[j] % p === 0 && j !== node && !visited[j]) {
                            queue.push(j);
                        }
                    }
                }
            }
        }
        steps++;
    }

    return -1; // Should never reach here if the array is valid
}

